mapper.insert:
INSERT INTO chat_room (chat_room_id, chat_room_name, room_type, created_by, created_at) 
VALUES (SEQ_CHAT_ROOM_ID.NEXTVAL, #{roomName}, 'SUPPORT', #{memberId}, SYSDATE
)

mapper.select:
SELECT chat_room_id AS chatRoomId, chat_room_name AS chatRoomName, room_type AS roomType, created_at AS createdAt
FROM   chat_room
WHERE  chat_room_id = #{chatRoomId}
